<script setup>
const votes = window.frusduellenMapData || {}

// Hardcoded example data for development
// const votes = {
//   finnmark: { jordbaer: 200, ananas: 52 },
//   troms: { jordbaer: 30, ananas: 70 },
//   nordland: { jordbaer: 25, ananas: 75 },
//   tronderlag: { jordbaer: 80, ananas: 20 },
//   'more-og-romsdal': { jordbaer: 60, ananas: 40 },
//   innlandet: { jordbaer: 65, ananas: 35 },
//   buskerud: { jordbaer: 40, ananas: 60 },
//   vestland: { jordbaer: 35, ananas: 65 },
//   oslo: { jordbaer: 50, ananas: 50 },
//   akershus: { jordbaer: 55, ananas: 45 },
//   rogaland: { jordbaer: 90, ananas: 10 },
//   telemark: { jordbaer: 100, ananas: 0 },
//   agder: { jordbaer: 0, ananas: 100 },
//   vestfold: { jordbaer: 45, ananas: 55 },
//   ostfold: { jordbaer: 52, ananas: 48 },
// }

// ===== Constants =====
const COLOR_JORDBAER = '#E5004E'
const COLOR_ANANAS = '#F6B901'
const COLOR_NEUTRAL = '#999999'

const BAR_TOTAL = 60
const BAR_GAP = 2

// ===== Helpers =====
function leaderColor(fylke) {
  const v = votes[fylke]
  if (!v) return COLOR_NEUTRAL
  if (v.jordbaer > v.ananas) return COLOR_JORDBAER
  if (v.ananas > v.jordbaer) return COLOR_ANANAS
  return COLOR_NEUTRAL
}

function jordbaerWidth(fylke) {
  const v = votes[fylke]
  if (!v) return 0
  const total = v.jordbaer + v.ananas
  if (total === 0) return 0
  if (v.ananas === 0) return BAR_TOTAL
  return (v.jordbaer / total) * (BAR_TOTAL - BAR_GAP)
}

function ananasWidth(fylke) {
  const v = votes[fylke]
  if (!v) return 0
  const total = v.jordbaer + v.ananas
  if (total === 0) return 0
  if (v.jordbaer === 0) return BAR_TOTAL
  return (v.ananas / total) * (BAR_TOTAL - BAR_GAP)
}

function ananasStart(fylke) {
  const jw = jordbaerWidth(fylke)
  if (jw === 0 || jw === BAR_TOTAL) return jw
  return jw + BAR_GAP
}
</script>

